mapper.insert:
INSERT INTO review (
    content, rating, image_org, image_new, visited_at, visited_time_zone,
    created_at, content_id, user_id, reservation_id
) VALUES (
    #{content}, #{rating}, #{image_org}, #{image_new}, #{visited_at}, #{visited_time_zone}, 
    NOW(), #{content_id}, #{user_id}, #{reservation_id}
)

mapper.update:
UPDATE review
SET 
	content = #{content},
    rating = #{rating},
    image_org = #{image_org},
    image_new = #{image_new}
WHERE review_id = #{review_id}
	AND user_id = #{user_id}

mapper.delete:
DELETE FROM review
WHERE review_id = #{review_id}
  	AND user_id = #{user_id}

mapper.select:
SELECT r.review_id, r.content, r.rating, r.image_org, r.image_new, r.visited_at, r.visited_time_zone, r.created_at, r.content_id, r.user_id, r.reservation_id, u.email FROM review r JOIN user u ON r.user_id = u.user_id WHERE r.content_id = #{content_id}
ORDER BY created_at DESC
ORDER BY rating DESC, created_at DESC
ORDER BY rating ASC, created_at DESC
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM review
WHERE reservation_id = #{reservation_id}

SELECT COUNT(*)
FROM review
WHERE content_id = #{content_id}
